import math


def sigma_m_deviation(
    sigma_cr_c: float, sigma_cr_p: float, N_Ed: float, b: float, a1: float, a2: float
) -> float:
    """Calculate the average stress for deviation forces.

    BS EN 1993-1-5:2006. Paragraph 9.2.1(5).

    Args:
        sigma_cr_c (float): Elastic critical column buckling stress in MPa.
        sigma_cr_p (float): Elastic critical plate buckling stress in MPa.
        N_Ed (float): Maximum compressive force of the adjacent panels in N.
        b (float): Span of the transverse stiffener in mm.
        a1 (float): Length of the adjacent panel 1 in mm.
        a2 (float): Length of the adjacent panel 2 in mm.

    Returns:
        float: The average stress sigma_m in MPa.
    """
    return (sigma_cr_c / sigma_cr_p) * (N_Ed / b) * (1 / a1 + 1 / a2)


def u_stiffener_parameter(
    E: float, e_max: float, f_y: float, b: float, gamma_M1: float = 1.0
) -> float:
    """Calculate the parameter u for stiffener requirement.

    BS EN 1993-1-5:2006. Paragraph 9.2.1(5).

    Args:
        E (float): Modulus of elasticity in MPa.
        e_max (float): Maximum distance from the extreme fibre to the centroid in mm.
        f_y (float): Yield strength of the steel in MPa.
        b (float): Span of the transverse stiffener in mm.
        gamma_M1 (float): Partial factor. Default value = 1.0.

    Returns:
        float: The parameter u, which must be >= 1.0.
    """
    u = (math.pi**2 * E * e_max) / ((f_y * 300 * b) / gamma_M1)
    return max(u, 1.0)


def Ist_min_transverse(
    sigma_m: float, E: float, b: float, w0: float, u: float
) -> float:
    """Calculate the minimum second moment of area for transverse stiffeners.

    BS EN 1993-1-5:2006. Eq. (9.1)

    Args:
        sigma_m (float): Average stress defined in 9.2.1(5) in MPa.
        E (float): Modulus of elasticity in MPa.
        b (float): Span of the transverse stiffener in mm.
        w0 (float): Initial sinusoidal imperfection in mm.
        u (float): Parameter defined in 9.2.1(5).

    Returns:
        float: The minimum second moment of area Ist in mm4.
    """
    return (sigma_m / E) * (b / math.pi) ** 4 * (1 + w0 * (300 / b) * u)


def delta_N_st_deviation(sigma_m: float, b: float) -> float:
    """Calculate the axial compression increase due to deviation forces.

    BS EN 1993-1-5:2006.

    Args:
        sigma_m (float): Average stress defined in 9.2.1(5) in MPa.
        b (float): Span of the transverse stiffener in mm.

    Returns:
        float: The additional axial force delta_N_st in N.
    """
    return (sigma_m * b**2) / (math.pi**2)


def q_equivalent_lateral_load(sigma_m: float, w0: float, w_el: float) -> float:
    """Calculate the equivalent uniformly distributed lateral load.

    BS EN 1993-1-5:2006. Eq. (9.2)

    Args:
        sigma_m (float): Average stress defined in 9.2.1(5) in MPa.
        w0 (float): Initial sinusoidal imperfection in mm.
        w_el (float): Elastic deformation (e.g., b/300) in mm.

    Returns:
        float: The equivalent lateral load q in N/mm.
    """
    return (math.pi / 4) * sigma_m * (w0 + w_el)


def check_torsional_buckling_it_ip(IT: float, Ip: float, f_y: float, E: float) -> bool:
    """Verify the criterion to prevent torsional buckling of open stiffeners.

    BS EN 1993-1-5:2006. Eq. (9.3)

    Args:
        IT (float): St. Venant torsional constant for the stiffener alone in mm4.
        Ip (float): Polar second moment of area around the edge fixed to the plate in mm4.
        f_y (float): Yield strength in MPa.
        E (float): Modulus of elasticity in MPa.

    Returns:
        bool: True if the criterion (IT/Ip >= 5.3 * fy/E) is satisfied.
    """
    return (IT / Ip) >= (5.3 * f_y / E)


def VEd_stiffener_cutout(
    I_net: float, e: float, f_yk: float, b_G: float, gamma_M0: float = 1.0
) -> float:
    """Calculate the shear force the web adjacent to a cutout must resist.

    BS EN 1993-1-5:2006. Eq. (9.5)

    Args:
        I_net (float): Second moment of area for the net section of the stiffener in mm4.
        e (float): Max distance from the underside of the flange to the neutral axis in mm.
        f_yk (float): Characteristic yield strength in MPa.
        b_G (float): Length of the transverse stiffener between flanges in mm.
        gamma_M0 (float): Partial factor. Default value = 1.0.

    Returns:
        float: The design shear force VEd in N.
    """
    return (I_net / e) * (f_yk / gamma_M0) * (math.pi / b_G)


def Ist_min_intermediate_rigid(a: float, hw: float, t: float) -> float:
    """Calculate the minimum inertia for intermediate rigid supports.

    BS EN 1993-1-5:2006. Eq. (9.6)

    Args:
        a (float): Distance between transverse stiffeners in mm.
        hw (float): Clear web depth between flanges in mm.
        t (float): Thickness of the web plate in mm.

    Returns:
        float: The minimum second moment of area Ist in mm4.
    """
    if (a / hw) < math.sqrt(2):
        return 1.5 * (hw**3 * t**3) / (a**2)
    else:
        return 0.75 * hw * t**3


def axial_force_intermediate_rigid(
    V_Ed: float,
    lambda_w_bar: float,
    f_yw: float,
    hw: float,
    t: float,
    gamma_M1: float = 1.0,
) -> float:
    """Calculate the axial force for designing rigid intermediate stiffeners.

    BS EN 1993-1-5:2006. Paragraph 9.3.3(3) NOTE.

    Args:
        V_Ed (float): Design shear force in N.
        lambda_w_bar (float): Modified slenderness for shear buckling.
        f_yw (float): Yield strength of the web in MPa.
        hw (float): Clear web depth between flanges in mm.
        t (float): Thickness of the web plate in mm.
        gamma_M1 (float): Partial factor. Default value = 1.0.

    Returns:
        float: The design axial force in the stiffener in N.
    """
    return V_Ed - (1.0 / lambda_w_bar**2) * f_yw * hw * t / (math.sqrt(3) * gamma_M1)
